class Solution:
    def lastNonEmptyString(self, s: str) -> str:
        from collections import deque, defaultdict

        freq = defaultdict(int)
        for ch in s:
            freq[ch] += 1

        max_freq = max(freq.values())
        result = []
        queue = deque()

        for ch in s:
            queue.append(ch)
            freq[ch] -= 1
            if freq[ch] == 0:
                while queue and freq[queue[0]] == 0:
                    queue.popleft()

        return ''.join(queue)
